<?php
namespace Tests\Feature;use App\Domain\Hunts\Data\HuntEnemyResult;use App\Domain\Hunts\Data\HuntResult;use App\Domain\Hunts\HuntService;use App\Models\Character;use App\Models\CharacterItem;use App\Models\CharacterWallet;use App\Models\GoldTransaction;use App\Models\Hunt;use App\Models\HuntEnemy;use App\Models\User;use App\Models\Zone;use App\Models\ZoneEncounterSize;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;class HuntServiceTest extends TestCase{use RefreshDatabase;public function test_hunt_persists_encounter_snapshot_without_rewards_or_health_changes(){$this->seed(WorldCatalogSeeder::class);$c=Character::factory()->for(User::factory())->create();$zone=Zone::where('code','grey_oak_forest')->first();$before=$c->fresh()->toArray();$experience=$c->experience;$r=app(HuntService::class)->start($c,$zone);$this->assertInstanceOf(HuntResult::class,$r);$this->assertSame(1,$r->enemyCount());$this->assertContainsOnlyInstancesOf(HuntEnemyResult::class,$r->enemies());$this->assertSame(1,Hunt::count());$this->assertSame(1,HuntEnemy::count());$this->assertSame($before,$c->fresh()->toArray());$this->assertSame($experience,$c->fresh()->experience);$this->assertSame(0,CharacterItem::count());$this->assertSame(0,CharacterWallet::count());$this->assertSame(0,GoldTransaction::count());$enemy=HuntEnemy::first();$old=$enemy->monster_name_snapshot;$enemy->monster->update(['name'=>'Renamed']);$this->assertSame($old,app(HuntService::class)->detail($c,$r->huntId())->enemies()[0]->monsterName());}public function test_one_two_three_and_repeated_enemies_have_consecutive_unique_instances(){$this->seed(WorldCatalogSeeder::class);foreach([1,2,3] as $count){$c=Character::factory()->for(User::factory())->create(['base_attack'=>500]);$zone=Zone::where('code','grey_oak_forest')->first();ZoneEncounterSize::where('zone_id',$zone->id)->delete();ZoneEncounterSize::create(['zone_id'=>$zone->id,'enemy_count'=>$count,'weight'=>100,'is_active'=>true,'sort_order'=>1]);$zone->monsters()->where('monsters.code','<>','grey_wolf')->updateExistingPivot($zone->monsters()->where('monsters.code','<>','grey_wolf')->pluck('monsters.id'),['status'=>'inactive']);$r=app(HuntService::class)->start($c,$zone);$this->assertSame($count,$r->enemyCount());$this->assertSame(range(1,$count),array_map(function($e){return$e->position();},$r->enemies()));$ids=array_map(function($e){return$e->instanceIdentifier();},$r->enemies());$this->assertCount($count,array_unique($ids));$this->assertSame($count,Hunt::find($r->huntId())->enemies()->count());}}public function test_detail_is_scoped_to_character_relation(){$this->seed(WorldCatalogSeeder::class);$a=Character::factory()->for(User::factory())->create();$b=Character::factory()->for(User::factory())->create();$h=app(HuntService::class)->start($a,Zone::where('code','grey_oak_forest')->first());$this->expectException(\Illuminate\Database\Eloquent\ModelNotFoundException::class);app(HuntService::class)->detail($b,$h->huntId());}}
